#include <stdio.h>
#include <stdlib.h>
typedef struct { int refcount; int value; } RefObj;
RefObj* create(int v) {
    RefObj *o = malloc(sizeof(RefObj));
    o->refcount = 1; o->value = v;
    return o;
}
void release(RefObj *o) {
    if(--o->refcount == 0) { free(o); }
}
int main() {
    RefObj *obj = create(42);
    printf("%d", obj->value);
    release(obj);
    return 0;
}

